package Array;
import java.util.Arrays;

public class SortingOfAnArray {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int a[]= {72,30,89,67,46,67,97};
		//to use this" Arrays" we neeed to import the package java.util.Arrays
		//to sort values of an array
		Arrays.sort(a);
		System.out.println(Arrays.toString(a));
		
		
		String names[]= {"Afrin","Hazeera","Ruffiya","Lahari","Tulasi","Indu","Mamatha","Ramya","Sajida","Sathwika"};
		Arrays.sort(names);
		System.out.println(Arrays.toString(names));
		
		
		
		
		
	}
}
